    ios::sync_with_stdio(false);

    cin.tie(nullptr);



    int N, M;

    cin >> N >> M;



    int L[M], R[M], C[M];

    for(int i = 0; i < M; i++){

        cin >> L[i] >> R[i] >> C[i] ;

        L[i]--; R[i]--; 

    }



